const clamp = (n) => Math.max(0, Math.min(10, n));

function usePersistentState(key, initial) {
  const [v, setV] = useState(() => {
    try { if (typeof window !== "undefined") { const s = window.localStorage.getItem(key); if (s != null) return JSON.parse(s); } } catch {}
    return initial;
  });
  React.useEffect(() => { try { if (typeof window !== "undefined") window.localStorage.setItem(key, JSON.stringify(v)); } catch {} }, [key, v]);
  return [v, setV];
}

